export function getKommunerByFylke(fylkeSlug: string): Kommune[] { return KOMMUNER.filter((k) => k.fylkeSlug === fylkeSlug); }

export function getFylke(slug: string): Fylke | undefined { return FYLKER.find((f) => f.slug === slug); }

export function getAllKommuneSlugs(): string[] { return KOMMUNER.map((k) => k.slug); }

export function getAllFylkeSlugs(): string[] { return FYLKER.map((f) => f.slug); }
